const body = $input.item.json.body || {};
const query = $input.item.json.query || {};
const channel = body.channel || query.channel || "unknown";
let sender_id, text, lang;
if (channel === "website_widget") {
  sender_id = body.session_id;
  text = (body.message || "").trim();
  lang = body.lang || "en";
} else if (channel === "whatsapp") {
  sender_id = body.From || body.from;
  text = (body.Body || body.body || "").trim();
  lang = "en";
} else if (channel === "instagram" || channel === "facebook") {
  const entry = body.entry && body.entry[0];
  const messaging = entry && (entry.messaging || (entry.changes && entry.changes[0] && entry.changes[0].value && entry.changes[0].value.messages));
  const msg = messaging && messaging[0];
  sender_id = msg && (msg.sender && msg.sender.id || msg.from);
  text = (msg && msg.message && msg.message.text || "").trim();
  lang = "en";
} else if (channel === "tawkto") {
  sender_id = body.chatId || (body.visitor && body.visitor.name);
  text = (body.message && (body.message.text || body.message) || "").trim();
  lang = "en";
} else {
  sender_id = "unknown";
  text = (body.message || "").trim();
  lang = "en";
}
return { json: {
  session_id: body.session_id || sender_id || "unknown",
  sender_id: sender_id || "unknown",
  text: text,
  channel: channel,
  lang: lang,
  hotel_slug: body.hotel_slug || "hotel",
  timestamp: new Date().toISOString()
} };

const msgData = $("Normalise Message").first().json;
const hotelInfoItems = $("Fetch Hotel Info").all();
const hotelInfo = {};
for (const item of hotelInfoItems) {
  if (item.json.key && item.json.value !== undefined) {
    hotelInfo[item.json.key] = String(item.json.value);
  }
}
const faqItems = $("Fetch FAQ").all();
const faqs = faqItems
  .filter(function(i) {
    return i.json.active === true || i.json.active === "TRUE" || i.json.active === "true";
  })
  .map(function(i) {
    return { category: i.json.category, question: i.json.question, answer: i.json.answer };
  });
const roomItems = $("Fetch Rooms").all();
const rooms = roomItems
  .filter(function(i) {
    return i.json.available === true || i.json.available === "TRUE" || i.json.available === "true";
  })
  .map(function(i) {
    return { type: i.json.type, rate: i.json.rate_per_night, capacity: i.json.capacity, description: i.json.description, amenities: i.json.amenities };
  });
return [{ json: {
  session_id: msgData.session_id,
  sender_id: msgData.sender_id,
  text: msgData.text,
  channel: msgData.channel,
  lang: msgData.lang,
  hotel_slug: msgData.hotel_slug,
  timestamp: msgData.timestamp,
  hotelInfo: hotelInfo,
  faqs: faqs,
  rooms: rooms
} }];

const data = $input.item.json || {};
const text = String(data.text || '');

if (text.trim().length < 3) {
  return { json: { ...data, lang: data.lang || 'en' } };
}

// STEP 1: Unicode range detection (non-Latin scripts — near 100% accurate)
const scriptRanges = [
  { lang: 'ar', regex: /[\u0600-\u06FF]/ },
  { lang: 'zh', regex: /[\u4E00-\u9FFF\u3400-\u4DBF]/ },
  { lang: 'ja', regex: /[\u3040-\u309F\u30A0-\u30FF]/ },
  { lang: 'ko', regex: /[\uAC00-\uD7AF]/ },
  { lang: 'ru', regex: /[\u0400-\u04FF]/ },
  { lang: 'th', regex: /[\u0E00-\u0E7F]/ },
  { lang: 'he', regex: /[\u0590-\u05FF]/ },
  { lang: 'el', regex: /[\u0370-\u03FF]/ },
  { lang: 'hi', regex: /[\u0900-\u097F]/ },
];
for (const script of scriptRanges) {
  if (script.regex.test(text)) {
    return { json: { ...data, lang: script.lang } };
  }
}

const tLower = text.toLowerCase();

// STEP 2: Tier 1 — unique multi-word phrases (1 match = definite detection)
// These phrases are impossible in English
const tier1 = {
  fr: ["bonjour","bonsoir","merci beaucoup","s'il vous","je voudrais","je suis","chambre disponible","comment allez","bienvenue","qu'est-ce"],
  es: ["hola","buenos dias","buenas tardes","buenas noches","gracias","habitacion","desayuno incluido","por favor","como estas"],
  de: ["guten morgen","guten tag","guten abend","danke schon","ich mochte","wie viel kostet","zimmer frei","auf wiedersehen"],
  it: ["buongiorno","buonasera","grazie mille","vorrei prenotare","camera disponibile","buona notte","prego"],
  pt: ["bom dia","boa tarde","boa noite","obrigado","obrigada","quarto disponivel","cafe da manha","bem-vindo"],
  nl: ["goedemorgen","goedemiddag","dank u wel","kamer beschikbaar","alstublieft","goedenavond"],
  tr: ["gunaydin","iyi aksamlar","tesekku ederim","oda musait","rezervasyon yapmak","hosgeldiniz"],
};
for (const lang in tier1) {
  for (const phrase of tier1[lang]) {
    if (tLower.includes(phrase)) {
      return { json: { ...data, lang: lang } };
    }
  }
}

// STEP 3: Tier 2 — weighted function words (min 3 matches required to avoid false positives)
// Words chosen to NOT overlap with common English words
const tier2 = {
  fr: ['les','est','qui','que','pour','avec','nous','vous','ils','elles','une','des','pas','sur','tres','mais','donc','bien','tout','alors','cette','aussi','quoi','quel','quelle','notre','votre','leur'],
  es: ['los','las','del','para','con','pero','hay','muy','como','cuando','donde','porque','tambien','todo','este','esta','tiene','tienen','hacer','nosotros','vosotros','ellos','ellas'],
  de: ['und','ist','nicht','auch','noch','dann','beim','nach','mehr','kann','will','sind','war','wird','habe','haben','mein','meine','keine','ihnen','ihrer','seine','unsere'],
  it: ['gli','sono','hanno','questo','questa','tutto','tutti','come','dove','quando','anche','pero','cosi','molto','bene','loro','siamo','avere','essere','nostro','vostro'],
  pt: ['sao','tem','com','por','para','tambem','quando','como','tudo','muito','aqui','nosso','nossa','voce','voces','eles','elas','sera','estar','fazer'],
  nl: ['het','zijn','heeft','niet','ook','meer','dan','nog','maar','want','omdat','toen','voor','door','over','naar','uit','bij','aan','van','wij','zij','jullie'],
  tr: ['var','yok','icin','gibi','ama','daha','cok','nasil','nerede','zaman','cunku','birlikte','hepsi','hic','bile','sadece','kadar','butun','olmak','etmek'],
};
const wordTokens = tLower.split(/\s+/);
const scores = {};
for (const lang in tier2) {
  let score = 0;
  for (const word of wordTokens) {
    const clean = word.replace(/[^a-z\u00e0-\u017e]/gi, '');
    if (tier2[lang].includes(clean)) score++;
  }
  scores[lang] = score;
}
const THRESHOLD = 3;
let bestLang = 'en';
let bestScore = 0;
for (const lang in scores) {
  if (scores[lang] >= THRESHOLD && scores[lang] > bestScore) {
    bestScore = scores[lang];
    bestLang = lang;
  }
}
return { json: { ...data, lang: bestLang } };

const agentRaw = $input.item.json;
const origData = $('Build System Prompt').item.json;

// Parse AI output — LangChain Agent outputs to 'output' field
let rawContent = null;
if (agentRaw.output !== undefined && agentRaw.output !== null && String(agentRaw.output).trim() !== '') {
  rawContent = String(agentRaw.output);
} else if (agentRaw.choices) {
  rawContent = (agentRaw.choices[0] && agentRaw.choices[0].message && agentRaw.choices[0].message.content) || null;
} else if (agentRaw.data && agentRaw.data.choices) {
  rawContent = (agentRaw.data.choices[0] && agentRaw.data.choices[0].message && agentRaw.data.choices[0].message.content) || null;
} else if (typeof agentRaw.data === 'string') {
  try { rawContent = JSON.parse(agentRaw.data).choices[0].message.content; } catch(e) {}
}

const fallbackReply = "I apologize, I'm having a technical issue right now. Please contact us at " +
  ((origData.hotelInfo && origData.hotelInfo.phone) || 'reception') + ' and we will be happy to help.';

let reply = rawContent || fallbackReply;

// ── Parse HANDOFF tag ────────────────────────────────────────────────────────
let handoff_required = false;
if (reply.includes('[HANDOFF_REQUIRED]')) {
  handoff_required = true;
  reply = reply.replace('[HANDOFF_REQUIRED]', '').trim();
}

// Keyword safety net — catches explicit requests the AI may have missed
const guestText = (origData.text || '').toLowerCase();
const humanKeywords = [
  'speak to someone','talk to someone','human please','real person',
  'live agent','speak with a person','customer service','manager please',
  'need a human','want to speak','talk to a person','let me speak',
  'speak to a manager','talk to manager','speak to staff','transfer me'
];
if (!handoff_required && humanKeywords.some(function(kw) { return guestText.includes(kw); })) {
  handoff_required = true;
  reply = "Of course! Let me connect you with a member of our team right away. Please hold for just a moment — they'll be with you shortly.";
}

// ── Parse LEAD tag ────────────────────────────────────────────────────────────
let lead_captured = false;
let lead_data = null;
const leadMatch = reply.match(/\[LEAD:\s*([^\]]+)\]/);
if (leadMatch) {
  lead_captured = true;
  const parts = leadMatch[1];
  const extract = function(key) {
    const m = parts.match(new RegExp(key + '=([^,\\]]+)'));
    return m ? m[1].trim() : null;
  };
  lead_data = {
    name: extract('name'),
    email: extract('email'),
    phone: extract('phone'),
    checkin: extract('checkin'),
    checkout: extract('checkout'),
  };
  // Strip tag — guest never sees it
  reply = reply.replace(/\[LEAD:[^\]]+\]/g, '').trim();
}

return {
  json: {
    session_id: origData.session_id,
    sender_id: origData.sender_id,
    channel: origData.channel,
    lang: origData.lang,
    hotel_slug: origData.hotel_slug,
    hotelInfo: origData.hotelInfo || {},
    text: origData.text || '',
    timestamp: origData.timestamp || new Date().toISOString(),
    reply: reply,
    handoff_required: handoff_required,
    lead_captured: lead_captured,
    lead_data: lead_data,
  }
};

// Email node response discarded — restore clean guest data from Extract AI Reply
const orig = $('Extract AI Reply').item.json;
return { json: orig };
